-- ================================================================
-- TB_ITEM007 데이터 정합성 수정 스크립트 (최종)
-- 작업 내용:
--   1. NEW_STS='ACQ' 이력 전체 삭제 (16,422건)
--   2. PREV_STS='ACQ', NEW_STS='OPER', 사유='신규 운용 등재'
--      → REQ_AT을 취득마스터 ACQ_AT으로 보정 (16,421건)
--   3. 위 이력들의 PREV_STS → NULL로 UPDATE (16,421건)
--   4. 신규 운용 등재 이력 없는 물품 64개 INSERT
-- ================================================================

USE usto;

-- ----------------------------------------------------------------
-- 1. NEW_STS='ACQ' 이력 전체 삭제 (16,422건)
-- ----------------------------------------------------------------
DELETE FROM TB_ITEM007
WHERE NEW_STS = 'ACQ';

-- ----------------------------------------------------------------
-- 2. REQ_AT 보정: 취득마스터 ACQ_AT 기준으로 수정 (16,421건)
--    (등록자/관리자는 기존 값 유지)
-- ----------------------------------------------------------------
UPDATE TB_ITEM007 h
    JOIN TB_ITEM002 d ON h.ITM_NO = d.ITM_NO
    JOIN TB_ITEM001M a ON d.ACQ_ID = a.ACQ_ID
SET h.REQ_AT = a.ACQ_AT,
    h.UPD_AT = NOW()
WHERE h.PREV_STS = 'ACQ'
  AND h.NEW_STS = 'OPER'
  AND h.CHG_RSN = '신규 운용 등재'
  AND h.DEL_YN = 'N';

-- ----------------------------------------------------------------
-- 3. PREV_STS='ACQ' → NULL로 UPDATE (16,421건)
-- ----------------------------------------------------------------
UPDATE TB_ITEM007
SET PREV_STS = NULL,
    UPD_AT = NOW()
WHERE PREV_STS = 'ACQ'
  AND NEW_STS = 'OPER'
  AND CHG_RSN = '신규 운용 등재';

-- ----------------------------------------------------------------
-- 4. 신규 운용 등재 이력 없는 물품 64개 INSERT
--    ITEM_HIS_ID: BINARY(16) → UNHEX(REPLACE(uuid, '-', '')) 방식
--    REQ_AT = 취득마스터 ACQ_AT, APPR_AT = 취득마스터 APPR_AT
-- ----------------------------------------------------------------

-- ================================================================
-- 검증 쿼리 (전부 0이 나와야 정상)
-- ================================================================
SELECT COUNT(*) AS acq_remaining FROM TB_ITEM007 WHERE NEW_STS = 'ACQ';
SELECT COUNT(*) AS prev_acq_remaining FROM TB_ITEM007 WHERE PREV_STS = 'ACQ';
SELECT COUNT(*) AS missing_oper_history
FROM TB_ITEM002 d
WHERE NOT EXISTS (
    SELECT 1 FROM TB_ITEM007 h
    WHERE h.ITM_NO = d.ITM_NO
      AND h.CHG_RSN = '신규 운용 등재'
      AND h.DEL_YN = 'N'
);